sys_ui_policy.script_false:
function onCondition() {
	if (g_form.getControl('u_external_ou')){
		g_form.setDisplay('u_external_ou', false);
		g_form.setReadOnly('u_external_ou', true);
		g_form.setDisabled('u_external_ou', true);
	}
	if (g_form.getControl('poc_name')){
		g_form.setDisplay('poc_name', false);
		g_form.setReadOnly('poc_name', true);
		g_form.setDisabled('poc_name', true);
	}
	if (g_form.getControl('external_task_id_number')){
		g_form.setDisplay('external_task_id_number', false);
		g_form.setReadOnly('external_task_id_number', true);
		g_form.setDisabled('external_task_id_number', true);
	}
	if (g_form.getControl('u_external_due_date')){
		g_form.setDisplay('u_external_due_date', false);
		g_form.setMandatory('u_external_due_date', false);
		g_form.setReadOnly('u_external_due_date', true);
		g_form.setDisabled('u_external_due_date', true);
	}
}

